import clsx from 'clsx';
import {
  type KeyboardEvent,
  useCallback,
  useEffect,
  useRef,
  useState,
  type HTMLAttributes,
} from 'react';
import { useIntl } from 'react-intl';

import { HistoryIcon } from '@dynatrace/strato-icons';

import type { PresetItemVariants } from './Presets.sty.js';
import * as styles from './Presets.sty.js';
import { useId } from '../../../../core/hooks/useId.js';
import { useFocusRing } from '../../../../core/styles/useFocusRing.js';
import { useTimeframeSelectorStore } from '../../../../core/time/timeframeStore/useTimeframeStore.js';
import type { BehaviorTrackingProps } from '../../../../core/types/behavior-tracking-props.js';
import type { DataTestId } from '../../../../core/types/data-props.js';
import type { StylingProps } from '../../../../core/types/styling-props.js';
import type { WithChildren } from '../../../../core/types/with-children.js';
import { mergeProps } from '../../../../core/utils/merge-props.js';
import {
  parseValue,
  removePrecisionFromTimeValue,
} from '../../../../forms/forms-core/time/timeParser.js';
import { Flex } from '../../../../layouts/flex/Flex.js';
import { Grid } from '../../../../layouts/grid/Grid.js';
import { Tooltip } from '../../../../overlays/tooltip/Tooltip.js';
import { Text } from '../../../../typography/text/Text.js';
import { TIMEFRAME_SELECTOR_MESSAGES } from '../../constants/timeframeSelectorMessages.js';
import { usePresetItemContext } from '../../hooks/usePresetItemContext.js';
import { useTimeframeSelectorContext } from '../../hooks/useTimeframeSelectorContext.js';
import { useTooltipMessages } from '../../hooks/useTooltipMessages.js';
import {
  isPresetSelected,
  saveRecentTimeframe,
} from '../../utils/presets-helpers.js';
import { isOutsideRange } from '../../utils/timeframe-selection.js';

//#region Typings

/**
 * @public
 */
export interface TimeframeSelectorPresetItemProps
  extends HTMLAttributes<HTMLLIElement>,
    DataTestId,
    StylingProps,
    WithChildren,
    BehaviorTrackingProps {
  /** The value of the timeframe preset. */
  value: {
    /** Start of the time frame. */
    from: string;
    /** End of the time frame. */
    to: string;
  };
}
//#endregion

/**
 * TimeframeSelector preset item shown inside the presets list of the overlay.
 * @public
 */
export const PresetItem = (
  props: TimeframeSelectorPresetItemProps & {
    // DEPRECATION: [APPDEV-16622] BREAKING-CHANGE: TimeframeSelector - Remove deprecated `_isSelected` prop.
    /**
     * @deprecated - Prop will be removed with the next breaking change cycle.
     */
    _isSelected?: boolean;
  },
) => {
  const {
    children,
    value,
    className: consumerClassName,
    style: consumerStyle,
    'data-testid': dataTestId,
    ...remainingProps
  }: TimeframeSelectorPresetItemProps & { _isSelected?: boolean } = props;

  const intl = useIntl();
  const [openTooltip, setOpenTooltip] = useState(false);

  const { details } = useTimeframeSelectorContext();

  const setValue = useTimeframeSelectorStore(
    (state) => state.setTimeframeSelectorTimeframe,
  );
  const min = useTimeframeSelectorStore((state) => state.min?.value);
  const max = useTimeframeSelectorStore((state) => state.max?.value);
  const precision = useTimeframeSelectorStore((state) => state.precision);

  const { isRecent } = usePresetItemContext();

  const isSelected = isPresetSelected(value, details, isRecent, precision);
  const isDisabled = isOutsideRange(value, min, max);

  const tooltipId = useId();
  const tooltipFocusProps = {
    onFocus: useCallback(
      () => !isDisabled && setOpenTooltip(true),
      [isDisabled],
    ),
    onBlur: useCallback(() => setOpenTooltip(false), []),
  };

  const { focusProps, focusClassName } = useFocusRing({
    color: isSelected && !isDisabled ? 'primary' : 'neutral',
    disabled: isDisabled,
  });

  let state: NonNullable<PresetItemVariants>['state'] = isSelected
    ? 'selected'
    : 'rest';
  if (isDisabled) {
    state = 'disabled';
  }

  const {
    timeframeDisplayValue,
    formattedPresetItemValue,
    tooltipFormattedTimeValueStart,
    tooltipFormattedTimeValueEnd,
    isAbsoluteTimeframe,
    isInvalid,
  } = useTooltipMessages(value, children);

  /** Handle clicking on the timeframe selector preset item. */
  const handleItemClick = useCallback(() => {
    if (isDisabled) {
      return;
    }

    const { from, to } = parseValue(value);

    if (from && to) {
      const timeframe = {
        from: removePrecisionFromTimeValue(from, precision) ?? from,
        to: removePrecisionFromTimeValue(to, precision) ?? to,
      };

      setValue(timeframe);
      saveRecentTimeframe(timeframe);
    }
  }, [isDisabled, value, precision, setValue]);

  /**
   * Temporary keydown listener to provide the possibility to select items via keyboard
   * Will change as soon as we switch to the reusable listbox component.
   */
  const handleItemKeyDown = useCallback(
    (event: KeyboardEvent<HTMLLIElement>) => {
      if (isDisabled) {
        return;
      }

      if (
        event.code === 'Enter' ||
        event.code === 'NumpadEnter' ||
        event.code === 'Space'
      ) {
        handleItemClick();
      }
    },
    [handleItemClick, isDisabled],
  );

  const liRef = useRef<HTMLLIElement | null>(null);

  useEffect(() => {
    if (isSelected) {
      liRef.current?.scrollIntoView({ block: 'nearest' });
    }
    // we don't want to scroll the element into view when isSelected changes, but only on the first render
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  if (isInvalid) {
    return null;
  }

  const tooltipContent = isDisabled ? (
    <Text textStyle="small">
      {intl.formatMessage(TIMEFRAME_SELECTOR_MESSAGES.disabledTooltip)}
    </Text>
  ) : (
    <Flex flexDirection="column">
      <Flex gap={0} flexDirection="column">
        <Text textStyle="base-emphasized">{timeframeDisplayValue}</Text>
        <Text textStyle="small">{formattedPresetItemValue}</Text>
      </Flex>
      {!isAbsoluteTimeframe && (
        <Flex gap={0} flexDirection="column">
          <Text textStyle="small">{tooltipFormattedTimeValueStart}</Text>
          <Text textStyle="small">{tooltipFormattedTimeValueEnd}</Text>
        </Flex>
      )}
    </Flex>
  );

  return (
    <li
      ref={liRef}
      role="option"
      aria-selected={isSelected}
      aria-disabled={isDisabled}
      className={clsx([
        focusClassName,
        styles.item({
          state,
        }),
        consumerClassName,
      ])}
      onClick={handleItemClick}
      onKeyDown={handleItemKeyDown}
      data-testid={dataTestId}
      style={consumerStyle}
      {...mergeProps(remainingProps, focusProps, tooltipFocusProps)}
    >
      <Tooltip
        id={tooltipId}
        text={tooltipContent}
        placement="right"
        fallbackPlacements={[
          'right-end',
          'bottom-end',
          'bottom',
          'bottom-start',
          'left-end',
          'left',
          'left-start',
        ]}
        open={openTooltip}
        onOpenChange={setOpenTooltip}
      >
        <div
          className={styles.wrapper({ isSelected, isDisabled })}
          aria-describedby={tooltipId}
        >
          <Grid className={styles.itemContainer}>
            <Flex alignItems="center" className={styles.displayValueWrapper}>
              {isRecent && <HistoryIcon className={styles.recentIcon} />}
              <Text
                textStyle="base-emphasized"
                as="div"
                className={styles.timeframeDisplayValue}
              >
                {timeframeDisplayValue}
              </Text>
            </Flex>
            {(!isRecent || !isAbsoluteTimeframe) && (
              <Text
                as={Flex}
                textStyle="small"
                className={clsx(
                  styles.mediaQuery,
                  styles.formattedPresetValue({
                    state,
                  }),
                )}
              >
                {formattedPresetItemValue}
              </Text>
            )}
          </Grid>
        </div>
      </Tooltip>
    </li>
  );
};

PresetItem.displayName = 'TimeframeSelector.PresetItem';
